module mux4 (invalid_out, in0, in1, sel0, sel1);

  output invalid_out;
  input in0, in1, sel0, sel1;

  reg invalid_out;

  always @ (sel1 or sel0 or in0 or in1) begin
    case ({sel1, sel0})
      2'b00: invalid_out = 1'b0;
      2'b01: invalid_out = in0;
      2'b10: invalid_out = in1;
      2'b11: invalid_out = 1'bx;
    endcase
  end

endmodule
